class Solution {
    public int numMusicPlaylists(int n, int goal, int k) {
        long mod = 1000000007;
        long[][] dp = new long[n + 1][goal + 1];
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= goal; j++) {
                dp[i][j] = dp[i - 1][j];
                if (j >= i) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - i]) % mod;
                }
                if (k > 0 && j >= i) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - i] * (j - i + 1)) % mod;
                }
            }
        }
        return (int) dp[n][goal];
    }
}
